import asyncio
import json
import uuid
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any

import websockets
from websockets.server import WebSocketServerProtocol


@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str


@dataclass
class Player:
    player_id: str
    websocket: WebSocketServerProtocol
    inventory: Set[str] = field(default_factory=set)
    balance: int = 0


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.player_locks: Dict[str, asyncio.Lock] = {}
        self.global_lock = asyncio.Lock()

    async def register_player(self, websocket: WebSocketServerProtocol, player_id: str) -> Player:
        async with self.global_lock:
            if player_id not in self.player_locks:
                self.player_locks[player_id] = asyncio.Lock()
            player = Player(player_id=player_id, websocket=websocket)
            self.players[player_id] = player
            return player

    async def unregister_player(self, player_id: str):
        async with self.global_lock:
            self.players.pop(player_id, None)

    async def create_item(self, owner_id: str, name: str) -> Item:
        async with self.global_lock:
            item = Item(item_id=str(uuid.uuid4()), name=name, owner_id=owner_id)
            self.items[item.item_id] = item
            if owner_id in self.players:
                self.players[owner_id].inventory.add(item.item_id)
            return item

    async def get_player(self, player_id: str) -> Optional[Player]:
        return self.players.get(player_id)

    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str) -> Dict[str, Any]:
        if from_player_id == to_player_id:
            return {"ok": False, "error": "cannot_transfer_to_self"}

        lock_a = self.player_locks.setdefault(from_player_id, asyncio.Lock())
        lock_b = self.player_locks.setdefault(to_player_id, asyncio.Lock())

        first_lock, second_lock = (lock_a, lock_b) if from_player_id < to_player_id else (lock_b, lock_a)

        async with first_lock:
            async with second_lock:
                from_player = self.players.get(from_player_id)
                to_player = self.players.get(to_player_id)
                if not from_player or not to_player:
                    return {"ok": False, "error": "player_not_found"}

                item = self.items.get(item_id)
                if not item:
                    return {"ok": False, "error": "item_not_found"}

                if item.owner_id != from_player_id:
                    return {"ok": False, "error": "not_item_owner"}

                if item_id not in from_player.inventory:
                    return {"ok": False, "error": "item_not_in_inventory"}

                from_player.inventory.remove(item_id)
                to_player.inventory.add(item_id)
                item.owner_id = to_player_id

                return {
                    "ok": True,
                    "item_id": item_id,
                    "from": from_player_id,
                    "to": to_player_id,
                }

    async def list_inventory(self, player_id: str) -> Dict[str, Any]:
        player = self.players.get(player_id)
        if not player:
            return {"ok": False, "error": "player_not_found"}

        items = [
            {"item_id": item_id, "name": self.items[item_id].name}
            for item_id in player.inventory
            if item_id in self.items
        ]
        return {"ok": True, "inventory": items, "balance": player.balance}

    async def handle_message(self, websocket: WebSocketServerProtocol, message: str):
        try:
            data = json.loads(message)
        except json.JSONDecodeError:
            await websocket.send(json.dumps({"ok": False, "error": "invalid_json"}))
            return

        action = data.get("action")
        player_id = data.get("player_id")

        if action == "register":
            if not player_id:
                await websocket.send(json.dumps({"ok": False, "error": "missing_player_id"}))
                return
            await self.register_player(websocket, player_id)
            await websocket.send(json.dumps({"ok": True, "action": "register", "player_id": player_id}))
            return

        if not player_id:
            await websocket.send(json.dumps({"ok": False, "error": "missing_player_id"}))
            return

        if action == "create_item":
            name = data.get("name")
            if not name:
                await websocket.send(json.dumps({"ok": False, "error": "missing_name"}))
                return
            item = await self.create_item(player_id, name)
            await websocket.send(json.dumps({"ok": True, "action": "create_item", "item": {
                "item_id": item.item_id,
                "name": item.name,
                "owner_id": item.owner_id,
            }}))
            return

        if action == "transfer_item":
            to_player_id = data.get("to_player_id")
            item_id = data.get("item_id")
            if not to_player_id or not item_id:
                await websocket.send(json.dumps({"ok": False, "error": "missing_transfer_fields"}))
                return
            result = await self.transfer_item(player_id, to_player_id, item_id)
            await websocket.send(json.dumps(result))
            return

        if action == "inventory":
            result = await self.list_inventory(player_id)
            await websocket.send(json.dumps(result))
            return

        await websocket.send(json.dumps({"ok": False, "error": "unknown_action"}))


server = GameServer()


async def connection_handler(websocket: WebSocketServerProtocol):
    player_id = None
    try:
        async for message in websocket:
            await server.handle_message(websocket, message)
    except websockets.exceptions.ConnectionClosed:
        pass
    finally:
        if player_id:
            await server.unregister_player(player_id)


async def main():
    async with websockets.serve(connection_handler, "0.0.0.0", 8765):
        await asyncio.Future()


if __name__ == "__main__":
    asyncio.run(main())